import React from 'react';
import type { OpenOrder, DcaOrder } from '../../types';
import { LoadingSpinner } from '../shared/LoadingSpinner';

export interface OpenOrdersTableProps {
  limitOrders: OpenOrder[];
  dcaOrders: DcaOrder[];
  isLoading: boolean;
  onCancel?: (orderId: string) => void;
  className?: string;
}

export function OpenOrdersTable({ limitOrders, dcaOrders, isLoading, onCancel, className = '' }: OpenOrdersTableProps) {
  if (isLoading) return <div className="ct-flex ct-justify-center ct-py-8"><LoadingSpinner /></div>;

  const empty = limitOrders.length === 0 && dcaOrders.length === 0;

  return (
    <div className={`ct-space-y-2 ${className}`}>
      {empty && (
        <div className="ct-text-center ct-py-8 ct-text-[hsl(var(--cedros-muted-foreground))] ct-text-sm">No open orders</div>
      )}

      {limitOrders.length > 0 && (
        <table className="ct-w-full ct-text-sm">
          <thead>
            <tr className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))] ct-border-b ct-border-[hsl(var(--cedros-border))]">
              <th className="ct-text-left ct-py-2 ct-px-2">Type</th>
              <th className="ct-text-left ct-py-2">Pair</th>
              <th className="ct-text-right ct-py-2">Amount</th>
              <th className="ct-text-right ct-py-2">Trigger</th>
              <th className="ct-text-right ct-py-2">Status</th>
              <th className="ct-text-right ct-py-2 ct-px-2"></th>
            </tr>
          </thead>
          <tbody>
            {limitOrders.map(o => (
              <tr key={o.orderId} className="ct-border-b ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))]">
                <td className="ct-py-2 ct-px-2">
                  <span className={`ct-px-2 ct-py-0.5 ct-rounded ct-text-xs ct-font-medium ${
                    o.orderType === 'stop-loss' ? 'ct-bg-red-500/10 ct-text-red-400' :
                    o.orderType === 'take-profit' ? 'ct-bg-green-500/10 ct-text-green-400' :
                    'ct-bg-blue-500/10 ct-text-blue-400'
                  }`}>{o.orderType}</span>
                </td>
                <td className="ct-py-2 ct-font-mono ct-text-xs">{o.inputMint.slice(0,4)}→{o.outputMint.slice(0,4)}</td>
                <td className="ct-py-2 ct-text-right">{o.inAmount}</td>
                <td className="ct-py-2 ct-text-right">{o.triggerPrice ?? '-'}</td>
                <td className="ct-py-2 ct-text-right">{o.status}</td>
                <td className="ct-py-2 ct-px-2 ct-text-right">
                  {onCancel && o.status === 'open' && (
                    <button onClick={() => onCancel(o.orderId)}
                      className="ct-text-xs ct-text-red-400 hover:ct-text-red-300">Cancel</button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {dcaOrders.length > 0 && (
        <div className="ct-space-y-2">
          <h4 className="ct-text-xs ct-font-medium ct-text-[hsl(var(--cedros-muted-foreground))] ct-px-2">DCA Schedules</h4>
          {dcaOrders.map(d => (
            <div key={d.dcaAccountId} className="ct-flex ct-items-center ct-justify-between ct-px-2 ct-py-2 ct-rounded ct-bg-[hsl(var(--cedros-muted))]">
              <div>
                <span className="ct-text-sm ct-text-[hsl(var(--cedros-foreground))]">
                  {d.completedCycles}/{d.totalCycles} cycles
                </span>
                <span className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))] ct-ml-2">{d.status}</span>
              </div>
              {d.nextCycleAt && (
                <span className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">
                  Next: {new Date(d.nextCycleAt).toLocaleDateString()}
                </span>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
