import React from 'react';
import { usePositions } from '../../hooks/usePositions';
import { PositionsTable } from '../trading/PositionsTable';
import { LoadingSpinner } from '../shared/LoadingSpinner';
import { ErrorMessage } from '../shared/ErrorMessage';

export interface PortfolioPageProps {
  walletAddress?: string;
  className?: string;
}

export function PortfolioPage({ walletAddress, className = '' }: PortfolioPageProps) {
  const { positions, isLoading, error, refresh } = usePositions(walletAddress ?? null);

  return (
    <div className={`ct-max-w-2xl ct-mx-auto ct-py-8 ct-px-4 ct-space-y-4 ${className}`}>
      <div className="ct-flex ct-items-center ct-justify-between">
        <h2 className="ct-text-xl ct-font-semibold ct-text-[hsl(var(--cedros-foreground))]">Portfolio</h2>
        <button onClick={refresh} disabled={isLoading}
          className="ct-text-sm ct-text-[hsl(var(--cedros-primary))] hover:ct-underline disabled:ct-opacity-50">
          Refresh
        </button>
      </div>

      {!walletAddress ? (
        <div className="ct-text-center ct-py-12 ct-text-[hsl(var(--cedros-muted-foreground))]">
          Connect a wallet to view your portfolio
        </div>
      ) : (
        <>
          <ErrorMessage message={error} />

          {/* Summary card */}
          {positions && (
            <div className="ct-bg-[hsl(var(--cedros-muted))] ct-rounded-cedros ct-p-4 ct-grid ct-grid-cols-2 ct-gap-4">
              <div>
                <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Total Value</div>
                <div className="ct-text-2xl ct-font-bold ct-text-[hsl(var(--cedros-foreground))]">${positions.totalValue}</div>
              </div>
              <div>
                <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Open Orders</div>
                <div className="ct-text-2xl ct-font-bold ct-text-[hsl(var(--cedros-foreground))]">{positions.openOrders}</div>
              </div>
            </div>
          )}

          <div className="ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-rounded-cedros">
            <PositionsTable
              holdings={positions?.holdings ?? []}
              isLoading={isLoading}
            />
          </div>
        </>
      )}
    </div>
  );
}
