import { useCallback, useState } from 'react';
import { useTradeApi } from '../context/CedrosTradeProvider';

export interface UseLimitOrderReturn {
  isLoading: boolean;
  error: string | null;
  createLimit: (params: { maker: string; inputMint: string; outputMint: string; inAmount: string; outAmount: string; expiry?: string }) => Promise<{ transaction: string; orderId: string }>;
  createStopLoss: (params: { maker: string; inputMint: string; outputMint: string; inAmount: string; triggerPrice: string; slippageBps?: number }) => Promise<{ transaction: string; orderId: string }>;
  createTakeProfit: (params: { maker: string; inputMint: string; outputMint: string; inAmount: string; triggerPrice: string; slippageBps?: number }) => Promise<{ transaction: string; orderId: string }>;
  createDca: (params: { maker: string; inputMint: string; outputMint: string; totalInAmount: string; perCycleAmount: string; cycleInterval: number }) => Promise<{ transaction: string; orderId: string }>;
}

export function useLimitOrder(): UseLimitOrderReturn {
  const api = useTradeApi();
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const wrap = useCallback(<T,>(fn: () => Promise<T>) => {
    return async () => {
      setIsLoading(true); setError(null);
      try { return await fn(); }
      catch (e: any) { setError(e.message); throw e; }
      finally { setIsLoading(false); }
    };
  }, []);

  const createLimit = useCallback(async (params: Parameters<typeof api.createLimitOrder>[0]) => {
    setIsLoading(true); setError(null);
    try { return await api.createLimitOrder(params); }
    catch (e: any) { setError(e.message); throw e; }
    finally { setIsLoading(false); }
  }, [api]);

  const createStopLoss = useCallback(async (params: Parameters<typeof api.createStopLoss>[0]) => {
    setIsLoading(true); setError(null);
    try { return await api.createStopLoss(params); }
    catch (e: any) { setError(e.message); throw e; }
    finally { setIsLoading(false); }
  }, [api]);

  const createTakeProfit = useCallback(async (params: Parameters<typeof api.createTakeProfit>[0]) => {
    setIsLoading(true); setError(null);
    try { return await api.createTakeProfit(params); }
    catch (e: any) { setError(e.message); throw e; }
    finally { setIsLoading(false); }
  }, [api]);

  const createDca = useCallback(async (params: Parameters<typeof api.createDca>[0]) => {
    setIsLoading(true); setError(null);
    try { return await api.createDca(params); }
    catch (e: any) { setError(e.message); throw e; }
    finally { setIsLoading(false); }
  }, [api]);

  return { isLoading, error, createLimit, createStopLoss, createTakeProfit, createDca };
}
