import React, { useEffect, useState } from 'react';
import { useTradeApi } from '../../context/CedrosTradeProvider';
import type { MonitoredOrder } from '../../types';
import { LoadingSpinner } from '../shared/LoadingSpinner';

export interface MonitoredOrdersListProps {
  walletAddress: string;
  className?: string;
}

export function MonitoredOrdersList({ walletAddress, className = '' }: MonitoredOrdersListProps) {
  const api = useTradeApi();
  const [orders, setOrders] = useState<MonitoredOrder[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    (api as any).get(`/orders/monitored/${walletAddress}`)
      .then((data: MonitoredOrder[]) => setOrders(data))
      .catch(() => {})
      .finally(() => setIsLoading(false));
  }, [api, walletAddress]);

  if (isLoading) return <div className="ct-flex ct-justify-center ct-py-4"><LoadingSpinner /></div>;
  if (orders.length === 0) return <div className="ct-text-center ct-py-4 ct-text-sm ct-text-[hsl(var(--cedros-muted-foreground))]">No monitored orders</div>;

  const statusColor = (s: string) => {
    switch (s) {
      case 'monitoring': return 'ct-text-blue-400';
      case 'executed': return 'ct-text-green-400';
      case 'cancelled': case 'failed': return 'ct-text-red-400';
      case 'action_pending': return 'ct-text-yellow-400';
      default: return 'ct-text-[hsl(var(--cedros-muted-foreground))]';
    }
  };

  return (
    <div className={`ct-space-y-2 ${className}`}>
      {orders.map(o => (
        <div key={o.id} className="ct-flex ct-items-center ct-justify-between ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))]">
          <div>
            <span className="ct-text-sm ct-font-medium ct-text-[hsl(var(--cedros-foreground))] ct-capitalize">{o.orderType.replace('-', ' ')}</span>
            {o.currentTrigger && <span className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))] ct-ml-2">Trigger: ${o.currentTrigger}</span>}
            {o.peakPrice && <span className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))] ct-ml-2">Peak: ${o.peakPrice}</span>}
          </div>
          <div className="ct-text-right">
            <span className={`ct-text-xs ct-font-medium ${statusColor(o.status)}`}>{o.status}</span>
            {o.fillPrice && <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Filled @ ${o.fillPrice}</div>}
          </div>
        </div>
      ))}
    </div>
  );
}
