import React, { createContext, useContext, useMemo } from 'react';
import { TradeApiClient } from '../utils/apiClient';
import { useTheme } from '../hooks/useTheme';
import type { CedrosTradeConfig } from '../types';
import type { ThemeMode, ThemeOverrides, UseThemeReturn } from '../hooks/useTheme';

interface TradeContextValue {
  api: TradeApiClient;
  config: CedrosTradeConfig;
  theme: UseThemeReturn;
}

const TradeContext = createContext<TradeContextValue | null>(null);

export interface CedrosTradeProviderProps {
  config: CedrosTradeConfig;
  children: React.ReactNode;
  /** Theme mode. Same prop name as cedros-login. Default: 'dark'. */
  theme?: ThemeMode;
  /**
   * Override CSS variable tokens. Same ThemeOverrides interface as cedros-login —
   * pass the same object to both providers and they'll both respect it.
   *
   * @example
   * const overrides = { '--cedros-background': '#292524', '--cedros-foreground': '#f5f5f4' };
   * <CedrosLoginProvider config={...} themeOverrides={overrides}>
   *   <CedrosTradeProvider config={...} themeOverrides={overrides}>
   */
  themeOverrides?: ThemeOverrides;
  /** Disable all default styles. Same prop as cedros-login's `unstyled`. */
  unstyled?: boolean;
}

export function CedrosTradeProvider({
  config, children, theme: themeMode = 'dark', themeOverrides, unstyled = false,
}: CedrosTradeProviderProps) {
  const themeState = useTheme(themeMode, themeOverrides);

  const value = useMemo(() => ({
    api: new TradeApiClient(config.serverUrl, config.getAccessToken, config.apiKey),
    config,
    theme: themeState,
  }), [config.serverUrl, config.apiKey, themeState]);

  if (unstyled) {
    return <TradeContext.Provider value={value}>{children}</TradeContext.Provider>;
  }

  // Class + inline style on same element so overrides always win over .cedros-dark defaults
  return (
    <TradeContext.Provider value={value}>
      <div className={themeState.className} style={themeState.style}>
        {children}
      </div>
    </TradeContext.Provider>
  );
}

export function useTradeContext(): TradeContextValue {
  const ctx = useContext(TradeContext);
  if (!ctx) throw new Error('useTradeContext must be used within <CedrosTradeProvider>');
  return ctx;
}

export function useTradeApi(): TradeApiClient {
  return useTradeContext().api;
}

/** Expose theme state. Same pattern as cedros-login's useThemeManager(). */
export function useCedrosTradeTheme(): UseThemeReturn {
  return useTradeContext().theme;
}
