import React, { useEffect, useState } from 'react';
import { useTradeApi } from '../../context/CedrosTradeProvider';
import type { SwapQuote } from '../../types';
import { LoadingSpinner } from '../shared/LoadingSpinner';

export interface ProviderComparisonProps {
  inputMint: string;
  outputMint: string;
  amount: string;
  outputDecimals?: number;
  onSelect?: (quote: SwapQuote) => void;
  className?: string;
}

export function ProviderComparison({ inputMint, outputMint, amount, outputDecimals = 6, onSelect, className = '' }: ProviderComparisonProps) {
  const api = useTradeApi();
  const [quotes, setQuotes] = useState<SwapQuote[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  useEffect(() => {
    if (!inputMint || !outputMint || !amount) return;
    setIsLoading(true);
    api.compareQuotes(inputMint, outputMint, amount)
      .then(setQuotes)
      .catch(() => setQuotes([]))
      .finally(() => setIsLoading(false));
  }, [api, inputMint, outputMint, amount]);

  if (isLoading) return <div className="ct-flex ct-justify-center ct-py-2"><LoadingSpinner className="ct-h-4 ct-w-4" /></div>;
  if (quotes.length <= 1) return null;

  const best = quotes.reduce((a, b) => BigInt(a.outAmount) > BigInt(b.outAmount) ? a : b);

  return (
    <div className={`ct-space-y-1 ${className}`}>
      <div className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Provider comparison</div>
      {quotes.map(q => {
        const isBest = q.provider === best.provider;
        const output = (parseInt(q.outAmount) / Math.pow(10, outputDecimals)).toFixed(4);
        return (
          <button key={q.provider} onClick={() => onSelect?.(q)}
            className={`ct-w-full ct-flex ct-items-center ct-justify-between ct-px-3 ct-py-1.5 ct-rounded ct-text-xs ct-transition ${
              isBest ? 'ct-bg-green-500/10 ct-border ct-border-green-500/30' : 'ct-bg-[hsl(var(--cedros-muted))] hover:ct-bg-[hsl(var(--cedros-border))]'
            }`}>
            <div className="ct-flex ct-items-center ct-gap-2">
              <span className="ct-font-medium ct-capitalize ct-text-[hsl(var(--cedros-foreground))]">{q.provider}</span>
              {q.gasless && <span className="ct-px-1.5 ct-py-0.5 ct-rounded ct-text-[10px] ct-bg-blue-500/10 ct-text-blue-400">Gasless</span>}
              {isBest && <span className="ct-px-1.5 ct-py-0.5 ct-rounded ct-text-[10px] ct-bg-green-500/10 ct-text-green-400">Best</span>}
            </div>
            <div className="ct-text-right">
              <span className="ct-font-mono ct-text-[hsl(var(--cedros-foreground))]">{output}</span>
              <span className="ct-text-[hsl(var(--cedros-muted-foreground))] ct-ml-1">({q.priceImpactPct.toFixed(2)}%)</span>
            </div>
          </button>
        );
      })}
    </div>
  );
}
