import { useMemo, useRef, useState } from 'react';

export type ThemeMode = 'light' | 'dark' | 'auto';

/**
 * Theme overrides — same interface as cedros-login's ThemeOverrides.
 * Uses CSS custom property names as keys so one set of overrides works across all Cedros packages.
 * Additional trade-specific tokens (--ct-*) are accepted via the index signature.
 */
export interface ThemeOverrides {
  '--cedros-primary'?: string;
  '--cedros-primary-foreground'?: string;
  '--cedros-background'?: string;
  '--cedros-foreground'?: string;
  '--cedros-muted'?: string;
  '--cedros-muted-foreground'?: string;
  '--cedros-border'?: string;
  '--cedros-input'?: string;
  '--cedros-ring'?: string;
  '--cedros-radius'?: string;
  '--cedros-destructive'?: string;
  '--cedros-destructive-foreground'?: string;
  /** Additional custom properties (e.g. --ct-buy, --ct-sell) */
  [key: string]: string | undefined;
}

export interface UseThemeReturn {
  mode: ThemeMode;
  setMode: (mode: ThemeMode) => void;
  isDark: boolean;
  className: string;
  style: React.CSSProperties;
}

function deepEqual(a: unknown, b: unknown): boolean {
  return JSON.stringify(a) === JSON.stringify(b);
}

export function useTheme(
  initialMode: ThemeMode = 'dark',
  overrides?: ThemeOverrides,
): UseThemeReturn {
  const [mode, setMode] = useState<ThemeMode>(initialMode);
  const prevRef = useRef(overrides);

  const stableOverrides = useMemo(() => {
    if (deepEqual(prevRef.current, overrides)) return prevRef.current;
    prevRef.current = overrides;
    return overrides;
  }, [overrides]);

  const isDark = mode === 'dark' || (mode === 'auto' && typeof window !== 'undefined' && window.matchMedia('(prefers-color-scheme: dark)').matches);

  const className = useMemo(() => {
    return `cedros-trade ${isDark ? 'cedros-dark' : ''}`.trim();
  }, [isDark]);

  const style = useMemo(() => {
    if (!stableOverrides) return {} as React.CSSProperties;
    const s: Record<string, string> = {};
    for (const [key, val] of Object.entries(stableOverrides)) {
      if (val) s[key] = val;
    }
    return s as React.CSSProperties;
  }, [stableOverrides]);

  return { mode, setMode, isDark, className, style };
}
