import React, { useState, useCallback } from 'react';
import { useLimitOrder } from '../../hooks/useLimitOrder';
import { useTradeApi } from '../../context/CedrosTradeProvider';
import { SlippageControl } from '../swap/SlippageControl';
import { AutoFeatures, defaultAutoFeatures } from './AutoFeatures';
import type { AutoFeaturesState } from './AutoFeatures';
import { LoadingSpinner } from '../shared/LoadingSpinner';
import { ErrorMessage } from '../shared/ErrorMessage';

export interface OrderFormProps {
  walletAddress?: string;
  inputMint: string;
  outputMint: string;
  inputSymbol?: string;
  outputSymbol?: string;
  currentPrice?: number;
  onSign?: (transaction: string) => Promise<string>;
  onSuccess?: (orderId: string) => void;
  className?: string;
}

type OrderTab = 'limit' | 'stop-loss' | 'take-profit' | 'trailing-stop' | 'oco' | 'bracket' | 'dca' | 'auto';

export function OrderForm({
  walletAddress, inputMint, outputMint, inputSymbol = '', outputSymbol = '',
  currentPrice, onSign, onSuccess, className = '',
}: OrderFormProps) {
  const { isLoading, error, createLimit, createStopLoss, createTakeProfit, createDca } = useLimitOrder();
  const api = useTradeApi();
  const [tab, setTab] = useState<OrderTab>('limit');
  const [side, setSide] = useState<'buy' | 'sell'>('buy');
  const [amount, setAmount] = useState('');
  const [price, setPrice] = useState('');
  const [slippageBps, setSlippageBps] = useState(100);
  const [dcaCycles, setDcaCycles] = useState('10');
  const [dcaInterval, setDcaInterval] = useState('86400');
  const [trailPercent, setTrailPercent] = useState('10');
  const [ocoSl, setOcoSl] = useState('');
  const [ocoTp, setOcoTp] = useState('');
  const [bracketSl, setBracketSl] = useState('10');
  const [bracketTp, setBracketTp] = useState('30');
  const [autoFeatures, setAutoFeatures] = useState<AutoFeaturesState>(defaultAutoFeatures);
  const [formError, setFormError] = useState<string | null>(null);

  const tabs: { id: OrderTab; label: string }[] = [
    { id: 'limit', label: 'Limit' },
    { id: 'stop-loss', label: 'Stop Loss' },
    { id: 'take-profit', label: 'Take Profit' },
    { id: 'trailing-stop', label: 'Trailing' },
    { id: 'oco', label: 'OCO' },
    { id: 'bracket', label: 'Bracket' },
    { id: 'dca', label: 'DCA' },
    { id: 'auto', label: 'Auto' },
  ];

  const inMint = side === 'buy' ? outputMint : inputMint;
  const outMint = side === 'buy' ? inputMint : outputMint;

  const handleSubmit = useCallback(async () => {
    if (!walletAddress || !onSign || !amount) return;
    setFormError(null);
    try {
      let result: { transaction: string; orderId: string };
      const maker = walletAddress;

      if (tab === 'limit') {
        if (!price) { setFormError('Enter a price'); return; }
        const decimals = 9;
        const inAmt = Math.round(parseFloat(amount) * Math.pow(10, decimals)).toString();
        const outAmt = Math.round(parseFloat(amount) * parseFloat(price) * Math.pow(10, 6)).toString();
        result = await createLimit({ maker, inputMint: inMint, outputMint: outMint, inAmount: inAmt, outAmount: outAmt });
      } else if (tab === 'stop-loss') {
        if (!price) { setFormError('Enter a trigger price'); return; }
        const inAmt = Math.round(parseFloat(amount) * Math.pow(10, 9)).toString();
        result = await createStopLoss({ maker, inputMint: inMint, outputMint: outMint, inAmount: inAmt, triggerPrice: price, slippageBps });
      } else if (tab === 'take-profit') {
        if (!price) { setFormError('Enter a trigger price'); return; }
        const inAmt = Math.round(parseFloat(amount) * Math.pow(10, 9)).toString();
        result = await createTakeProfit({ maker, inputMint: inMint, outputMint: outMint, inAmount: inAmt, triggerPrice: price, slippageBps });
      } else if (tab === 'trailing-stop') {
        const inAmt = Math.round(parseFloat(amount) * 1e9).toString();
        const data = await api.createTrailingStop({ maker, inputMint: inMint, outputMint: outMint, inAmount: inAmt, trailPercent: parseFloat(trailPercent), slippageBps });
        onSuccess?.(data.orderId); setAmount(''); return;
      } else if (tab === 'oco') {
        if (!ocoSl || !ocoTp) { setFormError('Enter both stop-loss and take-profit prices'); return; }
        const inAmt = Math.round(parseFloat(amount) * 1e9).toString();
        const data = await api.createOco({ maker, inputMint: inMint, outputMint: outMint, inAmount: inAmt, stopLoss: { triggerPrice: ocoSl, slippageBps }, takeProfit: { triggerPrice: ocoTp, slippageBps: 50 } });
        onSuccess?.(data.ocoId); setAmount(''); return;
      } else if (tab === 'bracket') {
        const inAmt = Math.round(parseFloat(amount) * 1e9).toString();
        const data = await api.createBracket({ maker, inputMint: inMint, outputMint: outMint, inAmount: inAmt, stopLossPercent: parseFloat(bracketSl), takeProfitPercent: parseFloat(bracketTp) });
        result = { transaction: data.entryTransaction, orderId: data.bracketId };
      } else if (tab === 'auto') {
        // Auto features: create orders for each enabled feature
        const inAmt = Math.round(parseFloat(amount) * 1e9).toString();
        const created: string[] = [];

        // Price targets → multiple take-profit orders (each sells a percentage)
        if (autoFeatures.targetsEnabled) {
          for (const target of autoFeatures.priceTargets) {
            if (!target.price || !target.percentage) continue;
            const pct = parseFloat(target.percentage) / 100;
            const targetAmt = Math.round(parseFloat(amount) * pct * 1e9).toString();
            const r = await createTakeProfit({ maker, inputMint: inMint, outputMint: outMint, inAmount: targetAmt, triggerPrice: target.price, slippageBps: 50 });
            await onSign(r.transaction);
            created.push(`TP@${target.price}`);
          }
        }

        // Profit protection → trailing stop
        if (autoFeatures.profitProtection.enabled && autoFeatures.profitProtection.dropPercent) {
          const trailAmt = autoFeatures.profitProtection.activateAbove ? inAmt : inAmt;
          await api.createTrailingStop({ maker, inputMint: inMint, outputMint: outMint, inAmount: trailAmt, trailPercent: parseFloat(autoFeatures.profitProtection.dropPercent), slippageBps: 100 });
          created.push(`Trail@${autoFeatures.profitProtection.dropPercent}%`);
        }

        // Stop loss → stop-loss order
        if (autoFeatures.stopLoss.enabled && autoFeatures.stopLoss.triggerPrice) {
          const r = await createStopLoss({ maker, inputMint: inMint, outputMint: outMint, inAmount: inAmt, triggerPrice: autoFeatures.stopLoss.triggerPrice, slippageBps: 100 });
          await onSign(r.transaction);
          created.push(`SL@${autoFeatures.stopLoss.triggerPrice}`);
        }

        // Trailing stop → trailing stop order
        if (autoFeatures.trailingStop.enabled && autoFeatures.trailingStop.trailPercent) {
          await api.createTrailingStop({ maker, inputMint: inMint, outputMint: outMint, inAmount: inAmt, trailPercent: parseFloat(autoFeatures.trailingStop.trailPercent), slippageBps: 100 });
          created.push(`Trail@${autoFeatures.trailingStop.trailPercent}%`);
        }

        if (created.length === 0) { setFormError('Enable at least one auto feature'); return; }
        onSuccess?.(created.join(', ')); setAmount(''); return;
      } else {
        // DCA
        const total = Math.round(parseFloat(amount) * Math.pow(10, 6)).toString();
        const perCycle = Math.round(parseFloat(amount) / parseInt(dcaCycles) * Math.pow(10, 6)).toString();
        result = await createDca({ maker, inputMint: inMint, outputMint: outMint, totalInAmount: total, perCycleAmount: perCycle, cycleInterval: parseInt(dcaInterval) });
      }

      await onSign(result.transaction);
      onSuccess?.(result.orderId);
      setAmount('');
      setPrice('');
    } catch (e: any) { setFormError(e.message); }
  }, [walletAddress, onSign, amount, price, tab, side, slippageBps, inMint, outMint, dcaCycles, dcaInterval, createLimit, createStopLoss, createTakeProfit, createDca, onSuccess]);

  return (
    <div className={`ct-bg-[hsl(var(--cedros-background))] ct-border ct-border-[hsl(var(--cedros-border))] ct-rounded-cedros ct-p-4 ct-space-y-3 ${className}`}>
      {/* Buy/Sell toggle */}
      <div className="ct-flex ct-gap-1 ct-p-1 ct-bg-[hsl(var(--cedros-muted))] ct-rounded-cedros">
        <button onClick={() => setSide('buy')}
          className={`ct-flex-1 ct-py-2 ct-rounded ct-text-sm ct-font-medium ct-transition ${side === 'buy' ? 'ct-bg-green-500 ct-text-white' : 'ct-text-[hsl(var(--cedros-muted-foreground))]'}`}>
          Buy
        </button>
        <button onClick={() => setSide('sell')}
          className={`ct-flex-1 ct-py-2 ct-rounded ct-text-sm ct-font-medium ct-transition ${side === 'sell' ? 'ct-bg-red-500 ct-text-white' : 'ct-text-[hsl(var(--cedros-muted-foreground))]'}`}>
          Sell
        </button>
      </div>

      {/* Order type tabs */}
      <div className="ct-flex ct-gap-1 ct-overflow-x-auto">
        {tabs.map(t => (
          <button key={t.id} onClick={() => setTab(t.id)}
            className={`ct-px-3 ct-py-1.5 ct-rounded ct-text-xs ct-font-medium ct-whitespace-nowrap ct-transition ${
              tab === t.id
                ? 'ct-bg-[hsl(var(--cedros-primary))] ct-text-[hsl(var(--cedros-primary-foreground))]'
                : 'ct-text-[hsl(var(--cedros-muted-foreground))] hover:ct-bg-[hsl(var(--cedros-muted))]'
            }`}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Price input (not for DCA) */}
      {tab !== 'dca' && (
        <div className="ct-space-y-1">
          <label className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">
            {tab === 'limit' ? 'Limit Price' : 'Trigger Price'}
          </label>
          <input type="text" value={price} onChange={e => setPrice(e.target.value)}
            placeholder={currentPrice ? currentPrice.toFixed(2) : '0.00'}
            className="ct-w-full ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none focus:ct-ring-2 focus:ct-ring-[hsl(var(--cedros-ring))]" />
        </div>
      )}

      {/* Amount input */}
      <div className="ct-space-y-1">
        <label className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Amount</label>
        <input type="text" value={amount} onChange={e => setAmount(e.target.value)} placeholder="0.00"
          className="ct-w-full ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none focus:ct-ring-2 focus:ct-ring-[hsl(var(--cedros-ring))]" />
        {/* Quick size buttons */}
        <div className="ct-flex ct-gap-1">
          {[25, 50, 75, 100].map(pct => (
            <button key={pct} className="ct-flex-1 ct-py-1 ct-text-xs ct-rounded ct-bg-[hsl(var(--cedros-muted))] ct-text-[hsl(var(--cedros-muted-foreground))] hover:ct-bg-[hsl(var(--cedros-border))]">
              {pct}%
            </button>
          ))}
        </div>
      </div>

      {/* DCA-specific fields */}
      {tab === 'dca' && (
        <div className="ct-grid ct-grid-cols-2 ct-gap-2">
          <div className="ct-space-y-1">
            <label className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Cycles</label>
            <input type="text" value={dcaCycles} onChange={e => setDcaCycles(e.target.value)}
              className="ct-w-full ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
          </div>
          <div className="ct-space-y-1">
            <label className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Interval</label>
            <select value={dcaInterval} onChange={e => setDcaInterval(e.target.value)}
              className="ct-w-full ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))]">
              <option value="3600">Hourly</option>
              <option value="86400">Daily</option>
              <option value="604800">Weekly</option>
            </select>
          </div>
        </div>
      )}

      {/* Trailing Stop fields */}
      {tab === 'trailing-stop' && (
        <div className="ct-space-y-1">
          <label className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))]">Trail Percentage</label>
          <div className="ct-flex ct-items-center ct-gap-2">
            <input type="number" value={trailPercent} onChange={e => setTrailPercent(e.target.value)} placeholder="10"
              className="ct-flex-1 ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
            <span className="ct-text-sm ct-text-[hsl(var(--cedros-muted-foreground))]">% below peak</span>
          </div>
        </div>
      )}

      {/* OCO fields */}
      {tab === 'oco' && (
        <div className="ct-grid ct-grid-cols-2 ct-gap-2">
          <div className="ct-space-y-1">
            <label className="ct-text-xs ct-text-red-400">Stop Loss Price</label>
            <input type="number" value={ocoSl} onChange={e => setOcoSl(e.target.value)} placeholder="130.00"
              className="ct-w-full ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-red-500/30 ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
          </div>
          <div className="ct-space-y-1">
            <label className="ct-text-xs ct-text-green-400">Take Profit Price</label>
            <input type="number" value={ocoTp} onChange={e => setOcoTp(e.target.value)} placeholder="200.00"
              className="ct-w-full ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-green-500/30 ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
          </div>
        </div>
      )}

      {/* Bracket fields */}
      {tab === 'bracket' && (
        <div className="ct-grid ct-grid-cols-2 ct-gap-2">
          <div className="ct-space-y-1">
            <label className="ct-text-xs ct-text-red-400">Stop Loss %</label>
            <input type="number" value={bracketSl} onChange={e => setBracketSl(e.target.value)} placeholder="10"
              className="ct-w-full ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-red-500/30 ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
          </div>
          <div className="ct-space-y-1">
            <label className="ct-text-xs ct-text-green-400">Take Profit %</label>
            <input type="number" value={bracketTp} onChange={e => setBracketTp(e.target.value)} placeholder="30"
              className="ct-w-full ct-px-3 ct-py-2 ct-rounded-cedros ct-bg-[hsl(var(--cedros-muted))] ct-border ct-border-green-500/30 ct-text-[hsl(var(--cedros-foreground))] ct-outline-none" />
          </div>
        </div>
      )}

      {/* Auto features (rockpile-style toggleable cards) */}
      {tab === 'auto' && (
        <AutoFeatures state={autoFeatures} onChange={setAutoFeatures} />
      )}

      {(tab === 'stop-loss' || tab === 'take-profit' || tab === 'trailing-stop') && (
        <SlippageControl value={slippageBps} onChange={setSlippageBps} />
      )}

      <ErrorMessage message={formError || error} onDismiss={() => setFormError(null)} />

      <button onClick={handleSubmit} disabled={!walletAddress || !amount || isLoading}
        className={`ct-w-full ct-py-3 ct-rounded-cedros ct-font-semibold ct-text-white ct-transition disabled:ct-opacity-50 disabled:ct-cursor-not-allowed ${
          side === 'buy' ? 'ct-bg-green-500 hover:ct-bg-green-600' : 'ct-bg-red-500 hover:ct-bg-red-600'
        }`}>
        {isLoading ? <LoadingSpinner /> : `${side === 'buy' ? 'Buy' : 'Sell'} ${inputSymbol}`}
      </button>
    </div>
  );
}
