import React from 'react';
import type { Holding } from '../../types';
import { LoadingSpinner } from '../shared/LoadingSpinner';

export interface PositionsTableProps {
  holdings: Holding[];
  isLoading: boolean;
  totalValue?: string;
  className?: string;
}

export function PositionsTable({ holdings, isLoading, totalValue, className = '' }: PositionsTableProps) {
  if (isLoading) return <div className="ct-flex ct-justify-center ct-py-8"><LoadingSpinner /></div>;

  return (
    <div className={className}>
      {totalValue && (
        <div className="ct-flex ct-justify-between ct-items-center ct-px-2 ct-py-2 ct-mb-2">
          <span className="ct-text-sm ct-text-[hsl(var(--cedros-muted-foreground))]">Total Value</span>
          <span className="ct-text-lg ct-font-semibold ct-text-[hsl(var(--cedros-foreground))]">${totalValue}</span>
        </div>
      )}

      {holdings.length === 0 ? (
        <div className="ct-text-center ct-py-8 ct-text-[hsl(var(--cedros-muted-foreground))] ct-text-sm">No holdings</div>
      ) : (
        <table className="ct-w-full ct-text-sm">
          <thead>
            <tr className="ct-text-xs ct-text-[hsl(var(--cedros-muted-foreground))] ct-border-b ct-border-[hsl(var(--cedros-border))]">
              <th className="ct-text-left ct-py-2 ct-px-2">Token</th>
              <th className="ct-text-right ct-py-2">Balance</th>
              <th className="ct-text-right ct-py-2">Price</th>
              <th className="ct-text-right ct-py-2 ct-px-2">Value</th>
            </tr>
          </thead>
          <tbody>
            {holdings.map(h => (
              <tr key={h.mint} className="ct-border-b ct-border-[hsl(var(--cedros-border))] ct-text-[hsl(var(--cedros-foreground))]">
                <td className="ct-py-2 ct-px-2 ct-font-medium">{h.symbol ?? h.mint.slice(0, 6)}</td>
                <td className="ct-py-2 ct-text-right ct-font-mono">{h.uiBalance}</td>
                <td className="ct-py-2 ct-text-right">{h.currentPrice ? `$${h.currentPrice}` : '-'}</td>
                <td className="ct-py-2 ct-px-2 ct-text-right ct-font-medium">{h.currentValue ? `$${h.currentValue}` : '-'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}
